namespace sv_9c3878b1a5ff4679afd55ec5ce377ffd.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with guanciale, Pecorino Romano, and black pepper.", 25),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts, vegetables, and chili peppers.", 35),
            new(5, "Mapo Tofu", "Silken tofu in a fiery Sichuan peppercorn and chili bean sauce.", 20),
            new(6, "Char Siu Pork", "Cantonese-style barbecue pork with honey glaze.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Spit-grilled pork tacos with pineapple, cilantro, and onion.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(9, "Chicken Enchiladas", "Corn tortillas filled with shredded chicken and smothered in salsa verde.", 50),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call
        await Task.Delay(2000, cancellationToken);

        if (RecipesByCuisine.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_9c3878b1a5ff4679afd55ec5ce377ffd.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2 d-inline-block" role="status">Refreshing…</div>
    }

    <ul class="list-group">
        @foreach (var recipe in GetSortedRecipes())
        {
            <li class="list-group-item">
                <h5>@recipe.Title</h5>
                <p class="mb-1">@recipe.Description</p>
                <small class="text-muted">Prep time: @recipe.PrepTimeMinutes min</small>
            </li>
        }
    </ul>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        // Only reload when CuisineId changes, not when sort changes
        if (_loadedCuisineId == CuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var cancellationToken = _cts.Token;
        var cuisineId = CuisineId;

        _error = null;
        _isRefreshing = _recipes is not null;

        if (!_isRefreshing)
        {
            StateHasChanged();
        }

        try
        {
            var results = await RecipeService.GetByCuisineAsync(cuisineId, cancellationToken);

            if (cancellationToken.IsCancellationRequested)
            {
                return;
            }

            _recipes = results;
            _loadedCuisineId = cuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException)
        {
            // Request was cancelled — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _isRefreshing = false;
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            _isRefreshing = false;
            _error = "Something went wrong loading recipes. Please try again.";
        }
    }

    private List<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return new();

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id).ToList(),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes).ToList(),
            _ => _recipes,
        };
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

